mapper.select:
SELECT d.id, d.id_site, d.id_device_type, d.id_device_group, s.`name` AS site_name, d.datatablename, d.devicename, d.field_value_default, dp.unit, IFNULL(dp.standard_name, dp.name) as parameter_name, DATE_FORMAT(CONVERT_TZ(d.last_updated,"UTC", t.`value`), "%M %d, %Y %h:%i:%s %p") AS last_updated, ROUND(IFNULL(d.field_value1, 0), 2) AS power_output, ROUND(IFNULL(d.energy_today, 0), 2) AS energy_today, ROUND(IFNULL(d.energy_yesterday, 0), 2) AS energy_yesterday, ROUND(IFNULL(d.energy_this_year, 0), 2) AS energy_this_year, ROUND(IFNULL(d.avg_daily_7days, 0), 2) AS avg_daily_7days, ROUND(IFNULL(d.avg_daily_last_7days, 0), 2) AS avg_daily_last_7days, t.id_error, t.start_date, t.end_date, t.message, IFNULL(t.error_code, 0) AS error_code,
t.id_error, t.id_error_type, t.id_error_level, t.error_level_name, t.error_type_name, t.color,
dt.image, dt.`name` as device_type_name, d.modbusdevicenumber, d.serial_number, d.rating_ac_power, d.serialnumber, d.note, IF( COUNT(tdm.id_device) = 0, JSON_ARRAY(), JSON_ARRAYAGG(JSON_OBJECT( 'id_tag', tg.id, 'tag_name', tg.`name` )) ) AS tags FROM device d LEFT JOIN device_type dt ON dt.id = d.id_device_type LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone LEFT JOIN ( SELECT a.id_device, e.message, e.error_code, a.note, a.start_date, a.end_date, a.id_error, e.id_error_type, e.id_error_level, el.`name` AS error_level_name, et.`name` AS error_type_name, el.color
FROM alert a LEFT JOIN device d ON d.id = a.id_device LEFT JOIN error e ON e.id = a.id_error LEFT JOIN error_level el ON el.id = e.id_error_level LEFT JOIN error_type et ON et.id = e.id_error_type
WHERE e.`status` = 1 AND e.is_delete = 0 AND a.`status` = 1 AND a.end_date IS NULL
AND el.id = #{id_error_level}
AND et.id = #{id_error_type}
GROUP BY d.id ) t ON t.id_device = d.id
LEFT JOIN device_group dg ON dg.id = d.id_device_group LEFT JOIN device_parameters dp ON dp.id_device_group = dg.id AND dp.slug = d.field_value_default LEFT JOIN tag_device_map tdm ON tdm.id_device = d.id LEFT JOIN tag tg ON tg.id = tdm.id_tag
LEFT JOIN site_employee_map esm ON esm.id_site = s.id
LEFT JOIN site_group_map sgm ON sgm.id_site = s.id
WHERE d.`status` = 1 AND d.is_delete = 0 AND s.`status` = 1 AND s.is_delete = 0
AND esm.id_employee = #{id_employee} AND esm.is_hiding = 0
AND sgm.id_site_group = #{id_site_group}
AND s.id = #{id_site}
AND dt.id = #{id_device_type}
AND id_error_level = #{id_error_level}
AND id_error_type = #{id_error_type}
AND s.name LIKE CONCAT("%",#{keyword}, "%")
AND error_code IS NOT NULL
AND error_code IS NULL
GROUP BY d.id
LIMIT ${limit} OFFSET ${offset};

SELECT count(*) as totalRow FROM(
SELECT d.id FROM device d LEFT JOIN device_type dt ON dt.id = d.id_device_type LEFT JOIN site s ON s.id = d.id_site LEFT JOIN time_zone t ON t.id = s.id_time_zone LEFT JOIN ( SELECT a.id_device, e.message, e.error_code, a.note, a.start_date, a.end_date, a.id_error, e.id_error_type, e.id_error_level, el.`name` AS error_level_name, et.`name` AS error_type_name, el.color
FROM alert a LEFT JOIN device d ON d.id = a.id_device LEFT JOIN error e ON e.id = a.id_error LEFT JOIN error_level el ON el.id = e.id_error_level LEFT JOIN error_type et ON et.id = e.id_error_type
WHERE e.`status` = 1 AND e.is_delete = 0 AND a.`status` = 1 AND a.end_date IS NULL
AND el.id = #{id_error_level}
AND et.id = #{id_error_type}
GROUP BY d.id ) t ON t.id_device = d.id
LEFT JOIN device_group dg ON dg.id = d.id_device_group
LEFT JOIN site_group_map sgm ON sgm.id_site = s.id
LEFT JOIN site_employee_map esm ON esm.id_site = s.id
WHERE d.`status` = 1 AND d.is_delete = 0 AND s.`status` = 1 AND s.is_delete = 0
AND esm.id_employee = #{id_employee} AND esm.is_hiding = 0
AND s.id = #{id_site}
AND sgm.id_site_group = #{id_site_group}
AND dt.id = #{id_device_type}
AND id_error_level = #{id_error_level}
AND id_error_type = #{id_error_type}
AND s.name LIKE CONCAT("%",#{keyword}, "%")
AND error_code IS NOT NULL
AND error_code IS NULL
GROUP BY d.id ) t
